     1→import { Injectable, Logger } from '@nestjs/common';
     2→import { OpenAI } from 'openai';
     3→
     4→import { getEnv } from '@utils/get-env-variable.util';
     5→
     6→import { OPENAI_API_KEY } from '@constants/env-variables.constant';
     7→
     8→import { MMSStyleToProcess } from '@interfaces/mms-style-to-process.interface';
     9→
    10→export interface ProductFeatureResponse {
    11→	description?: string[];
    12→	error?: string;
    13→}
    14→
    15→@Injectable()
    16→export class OpenAIService {
    17→	private readonly logger = new Logger(OpenAIService.name);
    18→	private readonly openai: OpenAI;
    19→
    20→	constructor() {
    21→		const apiKey = getEnv<string>({ key: OPENAI_API_KEY });
    22→		this.openai = new OpenAI({ apiKey, baseURL: 'https://api.openai.com/v1' });
    23→	}
    24→
    25→	async generateProductFeatures({
    26→		productInfo,
    27→	}: {
    28→		productInfo: MMSStyleToProcess;
    29→	}): Promise<ProductFeatureResponse> {
    30→		try {
    31→			this.logger.log(`Processing product features for id: ${productInfo.id}`);
    32→
    33→			const prompt = this.buildPrompt({ productInfo });
    34→
    35→			const response = await this.getOpenAIResponse(prompt);
    36→
    37→			this.logger.log(`Successfully generated features for id: ${productInfo.id}`);
    38→			return response;
    39→		} catch (error) {
    40→			this.logger.error(`Error processing product ${productInfo.id}:`, error);
    41→			return {
    42→				error: `Failed to process product: ${error instanceof Error ? error.message : 'Unknown error'}`,
    43→			};
    44→		}
    45→	}
    46→
    47→	private buildPrompt({ productInfo }: { productInfo: MMSStyleToProcess }): string {
    48→		return `
    49→The description should be present and be suitable for product recommendation model without mentioning names and brands.
    50→Description should be an array of feature strings.
    51→Response format: { "description": feature[] } in JSON format.
    52→
    53→Product in JSON format: ${JSON.stringify(productInfo, null, 2)}
    54→`;
    55→	}
    56→
    57→	private async getOpenAIResponse(prompt: string): Promise<ProductFeatureResponse> {
    58→		const completion = await this.openai.chat.completions.create({
    59→			messages: [
    60→				{
    61→					role: 'system',
    62→					content: `You are an expert in data preprocessing and feature engineering for machine learning.
    63→				Your job is prepare data for training Related Products model based on "Content-based" approach.
    64→				Your need to define key features, product details and important words for products and build array of features.
    65→          `,
    66→				},
    67→				{ role: 'user', content: [{ type: 'text', text: prompt }] },
    68→			],
    69→			model: 'gpt-4o',
    70→			response_format: { type: 'json_object' },
    71→		});
    72→
    73→		if (!completion.choices[0]) {
    74→			return { error: 'No response from OpenAI' };
    75→		}
    76→
    77→		const content = completion.choices[0].message.content;
    78→		if (!content) {
    79→			return { error: 'Empty response from OpenAI' };
    80→		}
    81→
    82→		try {
    83→			const parsedResponse = JSON.parse(content) as ProductFeatureResponse;
    84→
    85→			const fieldNames = Object.keys(parsedResponse);
    86→			const firstFieldName = fieldNames[0] as keyof ProductFeatureResponse;
    87→
    88→			if (!parsedResponse.description) {
    89→				const fieldValue = parsedResponse[firstFieldName];
    90→				return {
    91→					description:
    92→						typeof fieldValue === 'string'
    93→							? (JSON.parse(fieldValue) as string[])
    94→							: (fieldValue ?? []),
    95→					...parsedResponse,
    96→				};
    97→			}
    98→
    99→			return parsedResponse;
   100→		} catch (parseError) {
   101→			this.logger.error('Failed to parse OpenAI response:', parseError);
   102→			return { error: 'Failed to parse OpenAI response' };
   103→		}
   104→	}
   105→}
