     1→import * as os from 'os';
     2→import * as path from 'path';
     3→import { Worker, WorkerOptions } from 'worker_threads';
     4→
     5→import { Logger } from '@nestjs/common';
     6→import { Command, CommandRunner, Option } from 'nest-commander';
     7→
     8→import { rollbar } from '@config/rollbar.config';
     9→
    10→import { IProductAnnualSalesBase } from '@modules/db/product-annual-sales/types/product-annual-sales.base.interface';
    11→import { RenderTrendingResultsService } from '@modules/rest/trending-products/render-trending-results.service';
    12→import { TrendingProductsService } from '@modules/rest/trending-products/trending-products.service';
    13→
    14→import { ProgressBar } from '@utils/progress-bar.util';
    15→
    16→import { CompleteForecastResult } from '@interfaces/trending-products.interface';
    17→
    18→import { CronJobExecution } from '@decorators/cron-job-execution.decorator';
    19→
    20→type ForecastOptions = [string, string, string, string, string];
    21→
    22→interface WorkerResult {
    23→	success: boolean;
    24→	results?: CompleteForecastResult[];
    25→	error?: string;
    26→}
    27→
    28→@Command({
    29→	name: 'forecast-trending-products',
    30→	description:
    31→		'Analyze historical data and forecast trends for products for the next 7 days',
    32→})
    33→export class ForecastTrendingProductsCommand extends CommandRunner {
    34→	private readonly logger = new Logger(ForecastTrendingProductsCommand.name);
    35→	private readonly FORECAST_DAYS = 9;
    36→	private readonly PARALLEL_WORKERS = Math.min(os.cpus().length, 8);
    37→	private readonly BATCH_SIZE_PER_WORKER = 5;
    38→
    39→	constructor(
    40→		private readonly trendingProductsService: TrendingProductsService,
    41→		private readonly renderTrendingResultsService: RenderTrendingResultsService,
    42→	) {
    43→		super();
    44→	}
    45→
    46→	@Option({
    47→		flags: '-s, --start-date [string]',
    48→		description: 'Start date for analysis (YYYY-MM-DD)',
    49→	})
    50→	parseStartDate(val: string): string {
    51→		return val;
    52→	}
    53→
    54→	@Option({
    55→		flags: '-e, --end-date [string]',
    56→		description: 'End date for analysis (YYYY-MM-DD)',
    57→	})
    58→	parseEndDate(val: string): string {
    59→		return val;
    60→	}
    61→
    62→	@Option({
    63→		flags: '-p, --products [string]',
    64→		description: 'Comma-separated list of style_ids to analyze',
    65→	})
    66→	parseProducts(val: string): string {
    67→		return val;
    68→	}
    69→
    70→	@Option({
    71→		flags: '-b, --batch-size [number]',
    72→		description: 'Batch size for processing',
    73→	})
    74→	parseBatchSize(val: string): number {
    75→		return parseInt(val, 10);
    76→	}
    77→
    78→	@Option({
    79→		flags: '-f, --forecast-days [number]',
    80→		description: 'Number of days to forecast (default: 9)',
    81→	})
    82→	parseForecastDays(val: string): number {
    83→		return parseInt(val, 10) || this.FORECAST_DAYS;
    84→	}
    85→
    86→	@CronJobExecution({ jobName: 'forecast-trending-products' })
    87→	async run(passedParam: ForecastOptions): Promise<void> {
    88→		// TODO: need to use named parameters from options, not as indexed params from passedParam
    89→		const startDate = passedParam[0] || this.getDefaultStartDate();
    90→		const endDate = passedParam[1] || this.getDefaultEndDate();
    91→		const forecastDays = passedParam[4]
    92→			? parseInt(passedParam[4], 10)
    93→			: this.FORECAST_DAYS;
    94→
    95→		this.logger.log(`Forecasting trends from ${startDate} to ${endDate}`);
    96→
    97→		await this.trendingProductsService.invalidateLatestForecasts();
    98→
    99→		const productsData = await this.trendingProductsService.getStyleIdsInDateRange({
   100→			startDate,
   101→			endDate,
   102→		});
   103→
   104→		const productIds = productsData.reduce<number[]>((acc, product) => {
   105→			if (!acc.includes(product.style_id)) {
   106→				acc.push(product.style_id);
   107→			}
   108→			return acc;
   109→		}, []);
   110→
   111→		this.logger.log(`Found ${productIds.length} products with historical data`);
   112→
   113→		if (productIds.length === 0) {
   114→			this.logger.warn(
   115→				'No products found with historical data in the specified date range',
   116→			);
   117→			return;
   118→		}
   119→
   120→		const totalProducts = productIds.length;
   121→
   122→		const bar = new ProgressBar({ total: totalProducts });
   123→
   124→		const allResults = await this.processProductsInParallel({
   125→			productIds,
   126→			productsData,
   127→			startDate,
   128→			endDate,
   129→			forecastDays,
   130→			bar,
   131→		});
   132→
   133→		this.logger.log(
   134→			`Forecast completed. Processing ${allResults.length} results for database save.`,
   135→		);
   136→
   137→		const filtered = allResults
   138→			.filter((res) => res.predicted_orders.reduce((a, b) => a + b, 0) > 10)
   139→			.sort((a, b) => b.trend_score - a.trend_score);
   140→
   141→		const top30Results = filtered.slice(0, 30);
   142→
   143→		this.logger.log(
   144→			`Generating detailed HTML reports for top ${top30Results.length} trending products...`,
   145→		);
   146→		await this.renderTrendingResultsService.generateDetailedTrendingProductsReports(
   147→			top30Results,
   148→		);
   149→
   150→		this.logger.log('Activating latest predictions...');
   151→		await this.trendingProductsService.activateLatestPredictions();
   152→
   153→		this.logger.log('Forecast and report generation completed successfully');
   154→	}
   155→
   156→	private async processProductsInParallel({
   157→		productIds,
   158→		productsData,
   159→		startDate,
   160→		endDate,
   161→		forecastDays,
   162→		bar,
   163→	}: {
   164→		productIds: number[];
   165→		productsData: IProductAnnualSalesBase[];
   166→		startDate: string;
   167→		endDate: string;
   168→		forecastDays: number;
   169→		bar: ProgressBar;
   170→	}): Promise<CompleteForecastResult[]> {
   171→		const allResults: CompleteForecastResult[] = [];
   172→		const batchSize = this.BATCH_SIZE_PER_WORKER;
   173→		let processedCount = 0;
   174→
   175→		const batches: {
   176→			styleId: number;
   177→			historicalData: IProductAnnualSalesBase[];
   178→		}[][] = [];
   179→		for (let i = 0; i < productIds.length; i += batchSize) {
   180→			const batch = productIds
   181→				.slice(i, Math.min(i + batchSize, productIds.length))
   182→				.map((styleId) => ({
   183→					styleId,
   184→					historicalData: productsData.filter((item) => item.style_id === styleId),
   185→				}));
   186→			batches.push(batch);
   187→		}
   188→
   189→		this.logger.log(
   190→			`Processing ${productIds.length} products in ${batches.length} batches using ${this.PARALLEL_WORKERS} workers`,
   191→		);
   192→
   193→		for (let i = 0; i < batches.length; i += this.PARALLEL_WORKERS) {
   194→			const batchChunk = batches.slice(
   195→				i,
   196→				Math.min(i + this.PARALLEL_WORKERS, batches.length),
   197→			);
   198→
   199→			const chunkPromises = batchChunk.map((batch) =>
   200→				this.processInWorker({
   201→					batch,
   202→					startDate,
   203→					endDate,
   204→					forecastDays,
   205→				}),
   206→			);
   207→
   208→			const chunkResults = await Promise.allSettled(chunkPromises);
   209→
   210→			for (let j = 0; j < chunkResults.length; j++) {
   211→				const result = chunkResults[j];
   212→				const batch = batchChunk[j];
   213→
   214→				if (!result || !batch) continue;
   215→
   216→				if (result.status === 'fulfilled') {
   217→					const workerResult = result.value;
   218→					if (workerResult.success && workerResult.results) {
   219→						allResults.push(...workerResult.results);
   220→
   221→						if (workerResult.results.length > 0) {
   222→							try {
   223→								await this.trendingProductsService.saveBatchResults(
   224→									workerResult.results,
   225→									startDate,
   226→									endDate,
   227→									forecastDays,
   228→								);
   229→								this.logger.log(
   230→									`Saved ${workerResult.results.length} results to database`,
   231→								);
   232→							} catch (error) {
   233→								const err = error instanceof Error ? error : new Error(String(error));
   234→								this.logger.error(`Failed to save batch results: ${err.message}`);
   235→								rollbar.error(err, {
   236→									operation: 'saveBatchResults',
   237→									batchSize: workerResult.results.length,
   238→								});
   239→							}
   240→						}
   241→					}
   242→				} else {
   243→					this.logger.error(`Worker batch failed: ${result.reason}`);
   244→					rollbar.error(new Error(`Worker batch failed: ${result.reason}`), {
   245→						operation: 'processInWorker',
   246→						batchSize: batch.length,
   247→					});
   248→				}
   249→
   250→				processedCount += batch.length;
   251→				bar.increment(batch.length);
   252→				this.logger.log(
   253→					`Progress: ${processedCount}/${productIds.length} products processed`,
   254→				);
   255→			}
   256→		}
   257→
   258→		bar.finish();
   259→		return allResults;
   260→	}
   261→
   262→	private processInWorker({
   263→		batch,
   264→		startDate,
   265→		endDate,
   266→		forecastDays,
   267→	}: {
   268→		batch: { styleId: number; historicalData: IProductAnnualSalesBase[] }[];
   269→		startDate: string;
   270→		endDate: string;
   271→		forecastDays: number;
   272→	}): Promise<WorkerResult> {
   273→		return new Promise((resolve, reject) => {
   274→			const isDevelopment = process.env['NODE_ENV'] === 'development';
   275→			let workerPath: string;
   276→			if (isDevelopment) {
   277→				workerPath = path.resolve(__dirname, '..', 'workers', 'forecast-worker.ts');
   278→			} else {
   279→				workerPath = path.resolve(__dirname, '..', 'workers', 'forecast-worker.js');
   280→			}
   281→
   282→			const workerOptions: WorkerOptions = {
   283→				workerData: {
   284→					batch,
   285→					startDate,
   286→					endDate,
   287→					forecastDays,
   288→				},
   289→			};
   290→
   291→			if (isDevelopment) {
   292→				workerOptions.execArgv = [
   293→					'-r',
   294→					'ts-node/register',
   295→					'-r',
   296→					'tsconfig-paths/register',
   297→				];
   298→			}
   299→
   300→			const worker = new Worker(workerPath, workerOptions);
   301→			let resolved = false;
   302→
   303→			const cleanup = () => {
   304→				if (!resolved) {
   305→					resolved = true;
   306→					worker.terminate().catch(() => {
   307→						// Ignore termination errors
   308→					});
   309→				}
   310→			};
   311→
   312→			const timeout = setTimeout(() => {
   313→				cleanup();
   314→				reject(new Error('Worker timeout after 60 seconds'));
   315→			}, 60000);
   316→
   317→			worker.on('message', (result: WorkerResult) => {
   318→				clearTimeout(timeout);
   319→				cleanup();
   320→				resolve(result);
   321→			});
   322→
   323→			worker.on('error', (error) => {
   324→				clearTimeout(timeout);
   325→				cleanup();
   326→				reject(error);
   327→			});
   328→
   329→			worker.on('exit', (code) => {
   330→				clearTimeout(timeout);
   331→				if (code !== 0 && !resolved) {
   332→					cleanup();
