     8→import { runWithConcurrencyLimit } from '@utils/concurrency-pool.util';
     9→import { ProgressBar } from '@utils/progress-bar.util';
    10→
    11→import {
    12→	MMSAllStyleCategory,
    13→	MMSStyleToProcess,
    14→} from '@interfaces/mms-style-to-process.interface';
    15→
    16→import { CronJobExecution } from '@decorators/cron-job-execution.decorator';
    17→
    18→@Command({
    19→	name: 'sync-source-styles',
    20→	description: 'Sync source styles from MMS to Algolia index',
    21→})
    22→export class SyncStylesFromMMSCommand extends CommandRunner {
    23→	private readonly logger = new Logger(SyncStylesFromMMSCommand.name);
    24→	private readonly BATCH_SIZE = 20;
    25→	private readonly PARALLEL_WORKERS = 5;
    26→	private readonly MMS_TIMEOUT_MS = 50000;
    27→
    28→	constructor(
    29→		private readonly processStyleService: ProcessStyleService,
    30→		private readonly mmsService: MmsService,
    31→		private readonly styleAlternativesService: StyleAlternativesService,
    32→	) {
    33→		super();
    34→	}
    35→
    36→	@CronJobExecution({
    37→		jobName: 'sync-source-styles',
    38→		context: {
    39→			batchSize: 20,
    40→			parallelWorkers: 5,
    41→			timeoutMs: 50000,
    42→		},
    43→	})
    44→	async run(): Promise<void> {
    45→		const categories = await this.mmsService.fetchCategories();
    46→
    47→		const firstBatch = await this.processStyleService.fetchStylesFromMMS({
    48→			page: 1,
    49→			perPage: this.BATCH_SIZE,
    50→			timeoutMs: this.MMS_TIMEOUT_MS,
    51→		});
    52→		const totalStyles = firstBatch.total_entries;
    53→		const totalPages = Math.ceil(totalStyles / this.BATCH_SIZE);
    54→
    55→		this.logger.log(`Total styles: ${totalStyles}, Total pages: ${totalPages}`);
    56→
    57→		const bar = new ProgressBar({ total: totalStyles });
    58→
    59→		let processedStyles = 0;
    60→		let updatedStyles = 0;
    61→		let errorCount = 0;
    62→
    63→		const pages = Array.from({ length: totalPages }, (_, i) => i + 1);
    64→
    65→		await runWithConcurrencyLimit({
    66→			items: pages,
    67→			concurrency: this.PARALLEL_WORKERS,
    68→			handler: async (page) => {
    69→				return this.processPage({ page, categories, bar });
    70→			},
    71→			onItemComplete: (result) => {
    72→				processedStyles += result.processed;
    73→				updatedStyles += result.updated;
    74→
    75→				if (processedStyles % (this.BATCH_SIZE * 10) === 0) {
    76→					this.logger.log(
    77→						`Progress: ${processedStyles}/${totalStyles} processed, ${updatedStyles} updated, ${errorCount} errors`,
    78→					);
    79→				}
    80→			},
    81→			onItemError: (error, page) => {
    82→				errorCount++;
    83→				this.logger.error(`Failed to process page ${page}:`, error);
    84→			},
    85→		});
    86→
    87→		bar.finish();
    88→
    89→		this.logger.log(
    90→			`Sync completed. Processed: ${processedStyles}, Updated: ${updatedStyles}, Errors: ${errorCount}`,
    91→		);
    92→	}
    93→
    94→	private async processPage({
    95→		categories,
    96→		bar,
    97→		page,
    98→	}: {
    99→		page: number;
   100→		categories: MMSAllStyleCategory[];
   101→		bar: ProgressBar;
   102→	}): Promise<{ processed: number; updated: number }> {
   103→		const response = await this.processStyleService.fetchStylesFromMMS({
   104→			page,
   105→			perPage: this.BATCH_SIZE,
   106→			timeoutMs: this.MMS_TIMEOUT_MS,
   107→		});
   108→
   109→		if (response.styles.length === 0) {
   110→			return { processed: 0, updated: 0 };
   111→		}
   112→
   113→		let pageProcessed = 0;
   114→		let pageUpdated = 0;
   115→
   116→		for (const style of response.styles) {
   117→			const result = await this.processStyle({ style, categories });
   118→			pageProcessed++;
   119→
   120→			if (result.updated) {
   121→				pageUpdated++;
   122→			}
   123→
   124→			bar.increment(1, { updatedCount: pageUpdated });
   125→		}
   126→
   127→		return { processed: pageProcessed, updated: pageUpdated };
   128→	}
   129→
   130→	private async processStyle({
   131→		style,
   132→		categories,
   133→	}: {
   134→		style: MMSStyleToProcess;
   135→		categories: MMSAllStyleCategory[];
   136→	}): Promise<{ updated: boolean }> {
   137→		try {
   138→			const wasUpdated = await this.processStyleService.process({
   139→				style,
   140→				allCategories: categories,
   141→			});
   142→
   143→			await this.syncStyleAlternatives(style.id);
   144→
   145→			return { updated: wasUpdated };
   146→		} catch (error) {
   147→			this.logger.error(`Error processing style ${style.id}:`, error);
   148→			return { updated: false };
   149→		}
   150→	}
   151→
   152→	private async syncStyleAlternatives(styleId: number): Promise<void> {
   153→		try {
   154→			const complementsResponse = await this.mmsService.fetchStyleComplements(styleId);
   155→
   156→			if (!complementsResponse) {
   157→				return;
   158→			}
   159→
   160→			const alternativesComplement = complementsResponse.complements.find(
   161→				(c) => c.name === 'alternatives',
   162→			);
   163→
   164→			if (!alternativesComplement || alternativesComplement.style_ids.length === 0) {
   165→				return;
   166→			}
   167→
   168→			await this.styleAlternativesService.bulkUpsertStyleAlternatives({
   169→				styleId,
   170→				alternativeStyleIds: alternativesComplement.style_ids,
   171→			});
   172→
   173→			this.logger.debug(
   174→				`Synced ${alternativesComplement.style_ids.length} alternatives for style ${styleId}`,
   175→			);
   176→		} catch (error) {
   177→			this.logger.warn(
   178→				`Failed to sync alternatives for style ${styleId}: ${error instanceof Error ? error.message : String(error)}`,
   179→			);
   180→		}
   181→	}
   182→}
