   196→	async searchProducts({
   197→		query = '',
   198→		filters = '',
   199→		hitsPerPage = 20,
   200→	}: {
   201→		query?: string;
   202→		filters?: string;
   203→		hitsPerPage?: number;
   204→	}): Promise<{ hits: AlgoliaRelatedProductHit[] }> {
   205→		try {
   206→			const suffixFilter = `index_suffix:"${ALGOLIA_OBJECT_ID_SUFFIXES[0]}"`;
   207→			const combinedFilters = filters ? `(${filters}) AND ${suffixFilter}` : suffixFilter;
   208→
   209→			const searchResponse = await this.algoliaClient.search({
   210→				requests: [
   211→					{ indexName: this.indexName, query, filters: combinedFilters, hitsPerPage },
   212→				],
   213→			});
   214→
   215→			const firstResult = searchResponse.results[0];
   216→			if (firstResult && 'hits' in firstResult) {
   217→				return {
   218→					hits: firstResult.hits as AlgoliaRelatedProductHit[],
   219→				};
   220→			}
   221→
   222→			return { hits: [] };
   223→		} catch (error: unknown) {
   224→			this.handleError(
   225→				`Error searching products in Algolia with query "${query}" and filters "${filters}"`,
   226→				error,
   227→			);
   228→			throw new Error(`Failed to search products in Algolia`);
   229→		}
   230→	}
