   346→			const categoryFilter = categoryId ? `primary_category_id:${categoryId}` : '';
   347→			const combinedFilters = categoryFilter
   348→				? `(${brandFilters}) AND ${categoryFilter} AND ${suffixFilter}`
   349→				: `(${brandFilters}) AND ${suffixFilter}`;
   350→
   351→			const result = await this.algoliaClient.searchForHits({
   352→				requests: [
