/src/assets/embeddings/
└── product-embeddings-v1.bin       # Binary embedding storage
```

**Rationale**: Follows exact pattern from trending-products, related-products, and condensed-features modules.

---

## 2. REST Endpoint Design

### Route: `GET /semantic-search`

**Controller**: `/src/modules/rest/semantic-search/semantic-search.controller.ts`

```typescript
@ApiTags('semantic-search')
@Controller('semantic-search')
export class SemanticSearchController {
  constructor(
    private readonly semanticSearchService: SemanticSearchService,
    private readonly metricsService: MetricsService,
  ) {}

  @Get()
  @ApiOperation({ summary: 'Search products using natural language query' })
  @ApiResponse({ 
    status: 200, 
    description: 'Returns semantically similar products',
    type: SemanticSearchResponseDto 
  })
  @ApiResponse({ status: 400, description: 'Invalid query parameters' })
  @ApiResponse({ status: 500, description: 'Internal server error' })
  @ApiResponse({ status: 503, description: 'Embeddings not loaded' })
  @LogExecution({
    paramFormatter: (params: [SemanticSearchQueryDto]) => ({
      query: params[0].query?.substring(0, 50), // Truncate for logging
      limit: params[0].limit,
    }),
    responseFormatter: (response: SemanticSearchResponseDto) => ({
      resultsCount: response.products.length,
      topScore: response.products[0]?.similarity_score,
    }),
  })
  async search(
    @Query() query: SemanticSearchQueryDto,
  ): Promise<SemanticSearchResponseDto> {
    await this.metricsService.incrementDailyCounter(
      dailyTrackingKeys.SEMANTIC_SEARCH_REQUESTS,
    );
    return this.semanticSearchService.searchProducts(query);
  }
}
```

### Query DTO: `/src/dto/semantic-search/semantic-search-query.dto.ts`

```typescript
