## 3. CLI Command for Embedding Generation

### Command: `/src/modules/cli/commands/generate-product-embeddings.command.ts`

**Pattern**: Follow `forecast-trending-products.command.ts` with worker threads for CPU-intensive operations.

```typescript
@Command({
  name: 'generate-product-embeddings',
  description: 'Generate OpenAI embeddings for all active products',
})
export class GenerateProductEmbeddingsCommand extends CommandRunner {
  private readonly logger = new Logger(GenerateProductEmbeddingsCommand.name);
  private readonly BATCH_SIZE = 100; // OpenAI API batch size
  private readonly PARALLEL_WORKERS = 5; // Concurrent API calls
  private readonly EMBEDDING_MODEL = 'text-embedding-3-small';
  private readonly EMBEDDING_DIMENSIONS = 1536;

  constructor(
    private readonly openAIService: OpenAIService,
    private readonly stylesService: StylesService,
    private readonly productEmbeddingsService: ProductEmbeddingsService,
  ) {
    super();
  }

  @Option({
    flags: '-f, --full-rebuild',
    description: 'Rebuild all embeddings (default: incremental)',
  })
  parseFullRebuild(val: string): boolean {
    return val === 'true';
  }

  @Option({
    flags: '-o, --output [string]',
    description: 'Output file path',
  })
  parseOutput(val: string): string {
    return val;
  }

  @CronJobExecution({ jobName: 'generate-product-embeddings' })
  async run(passedParams: string[]): Promise<void> {
    const fullRebuild = passedParams[0] === 'true';
    const outputPath = passedParams[1] || 
      path.join(process.cwd(), 'src', 'assets', 'embeddings', 'product-embeddings-v1.bin');

    this.logger.log(`Starting embedding generation (fullRebuild: ${fullRebuild})`);

    // Step 1: Fetch all active products
    const allStyles = await this.stylesService.getAllActiveStyles();
    this.logger.log(`Found ${allStyles.length} active products`);

    // Step 2: Filter products that need embeddings
    const stylesToProcess = fullRebuild
      ? allStyles
      : await this.filterStylesNeedingEmbeddings(allStyles);

    this.logger.log(`Processing ${stylesToProcess.length} products`);

    // Step 3: Generate product descriptions
    const productDescriptions = stylesToProcess.map((style) =>
      this.buildProductDescription(style),
    );

    // Step 4: Generate embeddings with batching & concurrency
    const bar = new ProgressBar({ total: stylesToProcess.length });
    const embeddings = await this.generateEmbeddingsInBatches({
      descriptions: productDescriptions,
      styleIds: stylesToProcess.map(s => s.style_id),
      bar,
    });

    // Step 5: Save to database
    await this.productEmbeddingsService.bulkUpsert(embeddings);

    // Step 6: Write binary file
    await this.writeBinaryFile({ outputPath, embeddings });

    bar.finish();
    this.logger.log(`Successfully generated ${embeddings.length} embeddings`);
    this.logger.log(`Binary file saved to: ${outputPath}`);
  }

  private buildProductDescription(style: IStyleBase): string {
    // Rich description combining multiple fields
    const parts: string[] = [
      style.name,
      style.primary_category_name || '',
      style.broad_category_names?.join(', ') || '',
      style.sub_category_names?.join(', ') || '',
      style.decoration_method || '',
      style.features || '',
      style.general_comments || '',
      style.manufacturer || '',
      style.style_type || '',
      style.product_type || '',
      `Sizes: ${style.sizes?.join(', ')}`,
      `Min quantity: ${style.min_qty}`,
      style.no_minimum ? 'No minimum order' : '',
    ];

    return parts.filter(p => p.length > 0).join('. ');
  }

  private async generateEmbeddingsInBatches({
    descriptions,
    styleIds,
    bar,
  }: {
    descriptions: string[];
    styleIds: number[];
    bar: ProgressBar;
  }): Promise<Array<{ style_id: number; embedding: number[]; description: string }>> {
    const results: Array<{ style_id: number; embedding: number[]; description: string }> = [];

    // Split into batches
    for (let i = 0; i < descriptions.length; i += this.BATCH_SIZE) {
      const batch = descriptions.slice(i, i + this.BATCH_SIZE);
      const batchIds = styleIds.slice(i, i + this.BATCH_SIZE);

      try {
        // Use runWithConcurrencyLimit for parallel API calls
        const embeddings = await this.callOpenAIBatchEmbeddings(batch);

        for (let j = 0; j < embeddings.length; j++) {
          results.push({
            style_id: batchIds[j]!,
            embedding: embeddings[j]!,
            description: batch[j]!,
          });
          bar.increment(1);
        }

        // Rate limiting pause (OpenAI limits)
        await new Promise(resolve => setTimeout(resolve, 100));
      } catch (error) {
        this.logger.error(`Batch failed at index ${i}:`, error);
        rollbar.error(error as Error, { batch: i, size: batch.length });
        // Continue with next batch
      }
    }

    return results;
  }

  @LogExecution({
    paramFormatter: (params) => ({ batchSize: params.descriptions.length }),
    responseFormatter: () => '',
  })
  private async callOpenAIBatchEmbeddings(
    descriptions: string[],
  ): Promise<number[][]> {
    const response = await this.openAIService.createEmbeddings({
      model: this.EMBEDDING_MODEL,
      input: descriptions,
    });

    return response.data.map(item => item.embedding);
  }

  private async writeBinaryFile({
    outputPath,
    embeddings,
  }: {
    outputPath: string;
    embeddings: Array<{ style_id: number; embedding: number[]; description: string }>;
  }): Promise<void> {
    // Binary format: [version(4 bytes)][count(4 bytes)][records...]
    // Each record: [style_id(4 bytes)][embedding(1536*4 bytes)]

    const buffer = Buffer.alloc(8 + embeddings.length * (4 + this.EMBEDDING_DIMENSIONS * 4));
    let offset = 0;

    // Write version
    buffer.writeUInt32LE(1, offset);
    offset += 4;

    // Write count
    buffer.writeUInt32LE(embeddings.length, offset);
    offset += 4;

    // Write records
    for (const { style_id, embedding } of embeddings) {
      buffer.writeUInt32LE(style_id, offset);
      offset += 4;

      for (const value of embedding) {
        buffer.writeFloatLE(value, offset);
        offset += 4;
      }
    }

    await fs.promises.writeFile(outputPath, buffer);
  }

  private async filterStylesNeedingEmbeddings(
    styles: IStyleBase[],
  ): Promise<IStyleBase[]> {
    const existingEmbeddings = await this.productEmbeddingsService.getAllStyleIds();
    const existingSet = new Set(existingEmbeddings);
    return styles.filter(s => !existingSet.has(s.style_id));
  }
}
```

**Key Features**:
- **Batching**: Process 100 products per OpenAI API call (max 2048 per request)
- **Concurrency**: 5 parallel API calls with rate limiting
- **Progress tracking**: Using ProgressBar utility
- **Error handling**: Continue on batch failures, log to Rollbar
- **Incremental updates**: Only process new products (unless --full-rebuild)
- **Cost estimation**: Log total cost based on token count

---

## 4. Vector Storage & Loading

### Binary File Format

**Custom binary format** (most efficient for this use case):

```
Header (8 bytes):
  - Version (4 bytes, uint32): Format version for future compatibility
  - Count (4 bytes, uint32): Number of embeddings

Records (variable length):
  For each product:
    - Style ID (4 bytes, uint32)
    - Embedding (1536 * 4 bytes = 6144 bytes, float32[])
```

**Total size calculation**:
- Header: 8 bytes
- Per product: 4 + 6144 = 6148 bytes
- 30K products: 8 + (30000 × 6148) = ~184,440,008 bytes ≈ 176 MB

**File location**: `/src/assets/embeddings/product-embeddings-v1.bin`

**Alternative considered**: NPY format (NumPy) - rejected because requires additional library and adds complexity.

### Loading Strategy

**Service**: `/src/modules/rest/semantic-search/vector-search.service.ts`

```typescript
@Injectable()
export class VectorSearchService implements OnModuleInit {
  private readonly logger = new Logger(VectorSearchService.name);
  private embeddingsLoaded = false;
  private styleIds: number[] = [];
  private embeddings: Float32Array[] = [];
  private readonly EMBEDDING_DIMENSIONS = 1536;

  async onModuleInit(): Promise<void> {
    this.logger.log('Loading product embeddings into memory...');
    const startTime = Date.now();

    try {
      await this.loadEmbeddings();
      const loadTime = Date.now() - startTime;
      this.logger.log(
        `Loaded ${this.styleIds.length} embeddings in ${loadTime}ms (~${Math.round(process.memoryUsage().heapUsed / 1024 / 1024)}MB)`,
      );
      this.embeddingsLoaded = true;
    } catch (error) {
      this.logger.error('Failed to load embeddings:', error);
      rollbar.error(error as Error, { operation: 'loadEmbeddings' });
      // Don't throw - allow app to start, but mark as unavailable
    }
  }

  private async loadEmbeddings(): Promise<void> {
    const filePath = path.join(
      process.cwd(),
      'src',
      'assets',
      'embeddings',
      'product-embeddings-v1.bin',
    );

    if (!fs.existsSync(filePath)) {
      throw new Error(`Embeddings file not found: ${filePath}`);
    }

    const buffer = await fs.promises.readFile(filePath);
    let offset = 0;

    // Read header
    const version = buffer.readUInt32LE(offset);
    offset += 4;
    if (version !== 1) {
      throw new Error(`Unsupported embeddings version: ${version}`);
    }

    const count = buffer.readUInt32LE(offset);
    offset += 4;

    // Pre-allocate arrays
    this.styleIds = new Array(count);
    this.embeddings = new Array(count);

    // Read records
    for (let i = 0; i < count; i++) {
      const styleId = buffer.readUInt32LE(offset);
      offset += 4;

      const embedding = new Float32Array(this.EMBEDDING_DIMENSIONS);
      for (let j = 0; j < this.EMBEDDING_DIMENSIONS; j++) {
        embedding[j] = buffer.readFloatLE(offset);
        offset += 4;
      }

      this.styleIds[i] = styleId;
      this.embeddings[i] = embedding;
    }
  }

  isReady(): boolean {
    return this.embeddingsLoaded;
  }

  // Vector search implementation (see Section 6)
}
```

**Memory Management**:
- Use `Float32Array` for embeddings (efficient typed arrays)
- Pre-allocate arrays for performance
- Total memory: ~183 MB for 30K products
- Loaded once at startup, kept in memory

**Scaling Strategy**:
- **50K products**: ~305 MB (still manageable)
- **100K products**: ~610 MB (consider sharding or HNSW index)
- **Beyond 100K**: Migrate to vector database (Pinecone, Weaviate, pgvector)

---

## 5. Product Description Generation

### Strategy: Rich Multi-Field Description

**Implementation in CLI command**:

```typescript
private buildProductDescription(style: IStyleBase): string {
  const parts: string[] = [];

  // Core identification
  if (style.name) parts.push(`Product: ${style.name}`);
  if (style.brand?.length) parts.push(`Brand: ${style.brand.join(', ')}`);

  // Categories (critical for semantic matching)
  if (style.primary_category_name) {
    parts.push(`Category: ${style.primary_category_name}`);
  }
  if (style.broad_category_names?.length) {
    parts.push(`Type: ${style.broad_category_names.join(', ')}`);
  }
  if (style.sub_category_names?.length) {
    parts.push(`Subcategory: ${style.sub_category_names.join(', ')}`);
  }

  // Features (rich semantic content)
  if (style.features) parts.push(`Features: ${style.features}`);
  if (style.material) parts.push(`Material: ${style.material}`);
  if (style.general_comments) parts.push(style.general_comments);

  // Technical details
  if (style.decoration_method) {
    parts.push(`Decoration: ${style.decoration_method}`);
  }
  if (style.sizes?.length) {
    parts.push(`Available sizes: ${style.sizes.join(', ')}`);
  }
  if (style.style_type) parts.push(`Style type: ${style.style_type}`);
  if (style.product_type) parts.push(`Product type: ${style.product_type}`);

  // Order details
  if (style.no_minimum) {
    parts.push('No minimum order quantity');
  } else if (style.min_qty) {
    parts.push(`Minimum order: ${style.min_qty} units`);
  }

  if (style.turn_time) {
    parts.push(`Standard turnaround: ${style.turn_time} days`);
  }
  if (style.rush_turn_time) {
    parts.push(`Rush turnaround: ${style.rush_turn_time} days`);
  }

  // Manufacturer context
  if (style.manufacturer) parts.push(`Manufacturer: ${style.manufacturer}`);

  return parts.join('. ').trim();
}
```

**Data Sources**:
1. **Primary**: `styles` table (name, categories, features, technical specs)
2. **Secondary**: `style_colors` table (color information, could enhance with color names)
3. **Not used**: Algolia (to avoid circular dependency during generation)

**Description Quality**:
- Average length: ~200 words per product
- Rich semantic context for embeddings
- Structured format for consistency
- Handles missing fields gracefully

**Token Cost Estimation**:
- ~200 words × 1.3 tokens/word = ~260 tokens per product
- 30K products × 260 tokens = 7,800,000 tokens
- Cost: 7.8M tokens × $0.00002/1K = **$0.156** (one-time)

