## 6. Vector Search Implementation

### Service: `/src/modules/rest/semantic-search/semantic-search.service.ts`

```typescript
@Injectable()
export class SemanticSearchService {
  private readonly logger = new Logger(SemanticSearchService.name);

  constructor(
    private readonly vectorSearchService: VectorSearchService,
    private readonly openAIService: OpenAIService,
    private readonly productHydrationService: ProductHydrationService,
  ) {}

  async searchProducts(
    query: SemanticSearchQueryDto,
  ): Promise<SemanticSearchResponseDto> {
    // Check if embeddings are loaded
    if (!this.vectorSearchService.isReady()) {
      throw new ServiceUnavailableException(
        'Semantic search is temporarily unavailable. Embeddings not loaded.',
      );
    }

    this.logger.log('Processing semantic search query', {
      query: query.query.substring(0, 50),
      limit: query.limit,
    });

    // Step 1: Generate embedding for user query
    const queryEmbedding = await this.generateQueryEmbedding(query.query);

    // Step 2: Find similar products using cosine similarity
    const similarProducts = this.vectorSearchService.findSimilar({
      queryEmbedding,
      topK: query.limit ?? 20,
      minSimilarity: query.minSimilarity ?? 0.7,
      categoryFilter: query.categoryIds,
    });

    this.logger.log(`Found ${similarProducts.length} similar products`);

    // Step 3: Hydrate product data
    const styleIds = similarProducts.map(p => p.styleId);
    const hydratedProducts = await this.productHydrationService.hydrateProducts({
      styleIds,
      currentStyleColor: null,
    });

    // Step 4: Merge similarity scores with product data
    const productsWithScores = hydratedProducts.map((product) => {
      const similarProduct = similarProducts.find(p => p.styleId === product.style_id);
      return {
        ...product,
        similarity_score: similarProduct?.similarity ?? 0,
      };
    });

    // Step 5: Sort by similarity (descending)
    productsWithScores.sort((a, b) => b.similarity_score - a.similarity_score);

    return {
      query: query.query,
      products: productsWithScores,
      total_found: similarProducts.length,
      embeddings_loaded: true,
    };
  }

  @LogExecution({
    paramFormatter: (params) => ({ query: params.query?.substring(0, 30) }),
    responseFormatter: () => '',
  })
  private async generateQueryEmbedding(query: string): Promise<Float32Array> {
    const response = await this.openAIService.createEmbedding({
      model: 'text-embedding-3-small',
      input: query,
    });

    return new Float32Array(response.data[0].embedding);
  }
}
```

### Vector Search Core: `/src/modules/rest/semantic-search/vector-search.service.ts`

```typescript
@Injectable()
export class VectorSearchService implements OnModuleInit {
  // ... (loading code from Section 4)

  findSimilar({
    queryEmbedding,
    topK,
    minSimilarity,
    categoryFilter,
  }: {
    queryEmbedding: Float32Array;
    topK: number;
    minSimilarity: number;
    categoryFilter?: number[];
  }): Array<{ styleId: number; similarity: number }> {
    if (!this.embeddingsLoaded) {
      return [];
    }

    // Calculate cosine similarity for all products
    const similarities: Array<{ styleId: number; similarity: number }> = [];

    for (let i = 0; i < this.embeddings.length; i++) {
      const embedding = this.embeddings[i]!;
      const styleId = this.styleIds[i]!;

      // Apply category filter if provided
      if (categoryFilter && categoryFilter.length > 0) {
        // TODO: Implement category lookup (requires style metadata)
        // For now, skip filtering - implement in phase 2
      }

      const similarity = this.cosineSimilarity(queryEmbedding, embedding);

      if (similarity >= minSimilarity) {
        similarities.push({ styleId, similarity });
      }
    }

    // Sort by similarity (descending) and return top K
    similarities.sort((a, b) => b.similarity - a.similarity);
    return similarities.slice(0, topK);
  }

  private cosineSimilarity(a: Float32Array, b: Float32Array): number {
    let dotProduct = 0;
    let normA = 0;
    let normB = 0;

    for (let i = 0; i < a.length; i++) {
      dotProduct += a[i]! * b[i]!;
      normA += a[i]! * a[i]!;
      normB += b[i]! * b[i]!;
    }

    if (normA === 0 || normB === 0) {
      return 0;
    }

    return dotProduct / (Math.sqrt(normA) * Math.sqrt(normB));
  }
}
```

**Performance Optimizations**:
1. **Typed Arrays**: Use `Float32Array` for SIMD optimizations
2. **Pre-filtering**: Filter by minSimilarity during calculation (avoid sorting all 30K)
3. **Early termination**: Could add if we find enough high-quality matches
4. **Benchmarking target**: <100ms for 30K vectors

**Library Alternatives Considered**:
- **faiss-node**: Rejected (complex C++ dependencies, overkill for 30K vectors)
- **hnswlib-node**: Rejected (native bindings, deployment complexity)
- **Pure JS**: **SELECTED** (simple, no dependencies, fast enough for scale)

**Scaling Threshold**:
- Pure JS: Works well up to ~100K vectors (<200ms)
- Beyond 100K: Consider HNSW or vector database

