## 12. Performance Optimization Details

### Benchmarking Targets

| Operation | Target | Scale |
|-----------|--------|-------|
| Vector search (30K) | <100ms | 1536-dim vectors |
| Query embedding | <200ms | OpenAI API call |
| Product hydration | <300ms | Algolia fetch |
| **Total request** | **<600ms** | End-to-end |

### Optimization Strategies

**1. Vector Search Optimization**

```typescript
// Pre-compute squared norms for all embeddings (at load time)
private embeddingNorms: Float32Array;

private async loadEmbeddings(): Promise<void> {
  // ... load embeddings

  // Pre-compute norms
  this.embeddingNorms = new Float32Array(this.embeddings.length);
  for (let i = 0; i < this.embeddings.length; i++) {
    let normSquared = 0;
    for (let j = 0; j < this.EMBEDDING_DIMENSIONS; j++) {
      normSquared += this.embeddings[i]![j]! ** 2;
    }
    this.embeddingNorms[i] = Math.sqrt(normSquared);
  }
}

// Optimized cosine similarity (reuse pre-computed norms)
private cosineSimilarityFast(
  queryEmbedding: Float32Array,
  queryNorm: number,
  productIndex: number,
): number {
  let dotProduct = 0;
  const embedding = this.embeddings[productIndex]!;

  for (let i = 0; i < this.EMBEDDING_DIMENSIONS; i++) {
    dotProduct += queryEmbedding[i]! * embedding[i]!;
  }

  return dotProduct / (queryNorm * this.embeddingNorms[productIndex]!);
}
```

**2. Early Termination**

```typescript
// Use min-heap to track top K results (avoids full sort)
findSimilar({ queryEmbedding, topK, minSimilarity }: FindSimilarParams) {
  const minHeap = new MinHeap(topK); // Custom implementation

  for (let i = 0; i < this.embeddings.length; i++) {
    const similarity = this.cosineSimilarityFast(queryEmbedding, queryNorm, i);

    if (similarity >= minSimilarity) {
      minHeap.push({ styleId: this.styleIds[i]!, similarity });
    }
  }

  return minHeap.toArray().sort((a, b) => b.similarity - a.similarity);
}
```

**3. Caching Strategy**

```typescript
// Cache frequent queries
@Injectable()
export class SemanticSearchService {
  private queryCache = new Map<string, SemanticSearchResponseDto>();
  private readonly CACHE_SIZE = 1000;
  private readonly CACHE_TTL = 3600000; // 1 hour

  async searchProducts(query: SemanticSearchQueryDto): Promise<SemanticSearchResponseDto> {
    const cacheKey = this.buildCacheKey(query);

    if (this.queryCache.has(cacheKey)) {
      this.logger.log('Cache hit for query');
      return this.queryCache.get(cacheKey)!;
    }

    const result = await this.performSearch(query);

    // Cache with LRU eviction
    if (this.queryCache.size >= this.CACHE_SIZE) {
      const firstKey = this.queryCache.keys().next().value;
      this.queryCache.delete(firstKey);
    }
    this.queryCache.set(cacheKey, result);

    return result;
  }
}
```

