### Phase 3: HNSW Index (100K+ products)

**Library**: `hnswlib-node` (C++ binding)

```typescript
import { HierarchicalNSW } from 'hnswlib-node';

async loadEmbeddings(): Promise<void> {
  this.index = new HierarchicalNSW('cosine', this.EMBEDDING_DIMENSIONS);
  this.index.initIndex(this.embeddings.length);

  for (let i = 0; i < this.embeddings.length; i++) {
    this.index.addPoint(this.embeddings[i]!, i);
  }
}

findSimilar({ queryEmbedding, topK }: FindSimilarParams) {
  const result = this.index.searchKnn(queryEmbedding, topK);
  return result.neighbors.map((idx, i) => ({
    styleId: this.styleIds[idx]!,
    similarity: 1 - result.distances[i]!, // Convert distance to similarity
  }));
}
```

**Performance**: ~10ms for 100K vectors (vs. ~200ms pure JS)

